<?php namespace App\Domains\Furniture\Services; class FurnitureItemService { public function create(array $data) { return \App\Domains\Furniture\Models\FurnitureItem::create($data); } public function update($id, array $data) { $furniture = \App\Domains\Furniture\Models\FurnitureItem::find($id); return $furniture ? $furniture->update($data) : false; } public function delete($id) { return \App\Domains\Furniture\Models\FurnitureItem::destroy($id); } public function list($tenantId) { return \App\Domains\Furniture\Models\FurnitureItem::where('tenant_id', $tenantId)->get(); } }
